        }
    };

    const status = getStatusConfig();

    return (
        <motion.div 
            layout 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="relative mb-8 overflow-hidden rounded-[2.5rem] group"
        >
            {/* Reveal Delete on Swipe */}
