import { createClient } from '@supabase/supabase-js';

// CLINICAL SECURITY: Environment variables are the EXCLUSIVE source for credentials.
// Hardcoded fallbacks removed to comply with Phase 0 remediation.
const supabaseUrl = (import.meta as any).env?.VITE_SUPABASE_URL || "";
const supabaseAnonKey = (import.meta as any).env?.VITE_SUPABASE_ANON_KEY || "";

/**
 * CLINICAL SAFETY: Validates configuration status.
 * Used by the root App component to enter "System Offline" state if keys are missing.
 */
export const isSupabaseConfigured = (): boolean => {
    return !!(supabaseUrl && supabaseAnonKey && supabaseUrl.startsWith('https://'));
};

let clientInstance: any = null;

export const getSupabase = () => {
    if (!clientInstance) {
        if (!isSupabaseConfigured()) {
            return null;
        }
        clientInstance = createClient(supabaseUrl, supabaseAnonKey);
    }
    return clientInstance;
};

// Standard client proxy for backward compatibility.
// If not configured, common methods will return descriptive error messages instead of crashing.
export const supabase = new Proxy({} as any, {
    get(_, prop) {
        const client = getSupabase();
        if (!client) {
            if (prop === 'auth') return { 
                getSession: async () => ({ data: { session: null }, error: null }), 
                onAuthStateChange: () => ({ data: { subscription: { unsubscribe: () => {} } } }),
                signInWithPassword: async () => ({ data: { user: null, session: null }, error: { message: "Configuration Error: Supabase keys missing." } }),
                signUp: async () => ({ data: { user: null, session: null }, error: { message: "Configuration Error: Supabase keys missing." } }),
                signOut: async () => ({ error: null }),
                resetPasswordForEmail: async () => ({ data: {}, error: { message: "Configuration Error: Supabase keys missing." } })
            };

            return { 
                from: () => ({
                    select: () => ({ eq: () => ({ order: () => ({ data: [], error: null }) }) }), 
                    upsert: async () => ({ error: { message: "Cloud storage unavailable: Configuration error." } }), 
                    insert: async () => ({ error: { message: "Cloud storage unavailable: Configuration error." } }), 
                    delete: () => ({ eq: () => ({ eq: () => ({ error: null }) }) }) 
                }),
                storage: { from: () => ({ upload: async () => ({ error: { message: "Storage disabled" } }), getPublicUrl: () => ({ data: { publicUrl: "" } }) }) }
            };
        }
        return client[prop];
    }
});

import { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient.ts';
import { Session } from '@supabase/supabase-js';

export type User = { name: string; email: string; id: string };

export const useAuthSession = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);
  const [configError, setConfigError] = useState(false);

  const timeoutRef = useRef<any>(null);

  useEffect(() => {
    // Phase 0 Check
    if (!isSupabaseConfigured()) {
        setConfigError(true);
        setLoading(false);
        return;
    }

    // Phase 6: Extended Resilience Timeout (6s)
    // Prevents race conditions on high-latency mobile clinical networks.
    timeoutRef.current = setTimeout(() => {
      if (loading) {
        console.warn("Clinical Auth handshake delayed. Maintaining state...");
      }
    }, 6000);

    // 1. Initial Session Check
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
      }
      clearTimeout(timeoutRef.current);
      setLoading(false);
    }).catch((err: any) => {
      console.error("Auth hydration error:", err);
      clearTimeout(timeoutRef.current);
      setLoading(false);
    });

    // 2. Auth State Listener
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
      } else {
        setUser(null);
        setIsLoggedIn(false);
      }
      setLoading(false);
    });

    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      subscription.unsubscribe();
    };
  }, []);

  const login = (userData: any) => {};
  const logout = async () => { 
    await supabase.auth.signOut();
    // Phase 4: Explicit cache purge on logout
    localStorage.removeItem('rx_history_cache');
    window.location.reload(); 
  };

  return { user, isLoggedIn, login, logout, loading, configError };
};

