                const { exportBulkPDF } = await import('../lib/pdfUtils.ts');
                await exportBulkPDF(history);
                triggerHaptic('success');
                showToast('Bulk PDF export started.', 'info');
            } catch (e) {
                console.error(e);
                showToast('Export failed.', 'error');
            } finally {
                setIsBulkDownloading(false);
