import React, { useState } from 'react';
import { GoogleIcon } from './icons/GoogleIcon.tsx';
import BrandLogo from './BrandLogo.tsx';
import { motion, AnimatePresence } from 'framer-motion';
import { Spinner } from './Spinner.tsx';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient.ts';

interface LoginModalProps {
  onLogin: (user: { name: string; email: string }) => void;
  onClose: () => void;
}

export const LoginModal: React.FC<LoginModalProps> = ({ onLogin, onClose }) => {
  const [view, setView] = useState<'login' | 'signup' | 'forgot'>('login');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const isConfigured = isSupabaseConfigured();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isConfigured) return;

    setError('');
    setLoading(true);

    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    setLoading(false);

    if (error) {
      setError(error.message);
    } else if (data.user) {
      onLogin({ 
        name: data.user.user_metadata?.full_name || email.split('@')[0], 
        email: data.user.email || '' 
      });
    }
  };

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isConfigured) return;

    setError('');
    setLoading(true);

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: {
          full_name: fullName,
        },
      },
    });

    setLoading(false);

    if (error) {
      setError(error.message);
    } else {
      setMessage('Registration successful! Please check your email to confirm your account.');
      setView('login');
    }
  };

  const handleResetSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!email || !isConfigured) return;

      setLoading(true);
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: window.location.origin,
      });
      setLoading(false);

      if (error) {
        setError(error.message);
      } else {
        setMessage('Check your email for the password reset link.');
        setView('login');
      }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center"
      onClick={onClose}
    >
      <motion.div 
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.9, opacity: 0 }}
        transition={{ type: "spring", stiffness: 300, damping: 25 }}
        className="bg-light-panel dark:bg-dark-panel w-full max-w-md m-4 rounded-2xl shadow-2xl p-8 border border-light-border dark:border-dark-border overflow-hidden"
        onClick={e => e.stopPropagation()}
      >
        <BrandLogo variant="full" className="mx-auto mb-6" />

        {!isConfigured ? (
            <div className="text-center py-6">
                <div className="w-16 h-16 bg-amber-100 dark:bg-amber-900/30 rounded-2xl flex items-center justify-center mx-auto mb-6 text-amber-600">
                    <span className="material-symbols-outlined text-3xl">cloud_off</span>
                </div>
                <h2 className="text-xl font-black text-light-text dark:text-dark-text tracking-tight uppercase">Local Workspace</h2>
                <p className="text-sm text-light-text-mid dark:text-dark-text-mid mt-4 leading-relaxed font-medium">
                    This clinical environment is configured for **Local Compliance Mode**. Cloud synchronization and central archiving are unavailable.
                </p>
                <div className="mt-8 pt-6 border-t border-light-border dark:border-dark-border">
                    <button 
                        onClick={onClose}
                        className="w-full py-4 bg-slate-900 dark:bg-white text-white dark:text-black rounded-xl font-black text-sm uppercase tracking-widest"
                    >
                        Return to Dashboard
                    </button>
                </div>
            </div>
        ) : (
            <AnimatePresence mode="wait">
                {view === 'login' && (
                    <motion.div
                        key="login"
                        initial={{ x: -20, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        exit={{ x: -20, opacity: 0 }}
                        transition={{ duration: 0.2 }}
