import { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient.ts';

export type User = { name: string; email: string; id: string };

export const useAuthSession = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);

  const timeoutRef = useRef<any>(null);

  useEffect(() => {
    // CAPABILITY CHECK: Defer infrastructure auditing to specific feature components.
    if (!isSupabaseConfigured()) {
        setLoading(false);
        return;
    }

    // Resilience Timeout for cloud handshake
    timeoutRef.current = setTimeout(() => {
      if (loading) {
        console.info("Clinical Auth: Waiting for secure handshake...");
      }
    }, 4000);

    // 1. Session Hydration
    // Using getSession safely and handling potential null data/session
    supabase.auth.getSession().then((result) => {
      const session = result?.data?.session;
      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
      } else {
        setUser(null);
        setIsLoggedIn(false);
      }
      clearTimeout(timeoutRef.current);
      setLoading(false);
    }).catch((err) => {
      console.warn("Auth session fetch error:", err);
      setLoading(false);
    });

    // 2. State Listener
    const authListener = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
      } else {
        setUser(null);
        setIsLoggedIn(false);
      }
      setLoading(false);
    });

    // Handle potential differences in return shape for subscription
    const subscription = authListener?.data?.subscription || authListener?.subscription || authListener;

    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      if (subscription && typeof subscription.unsubscribe === 'function') {
        subscription.unsubscribe();
      }
    };
  }, []);

  const login = (userData: any) => {};
  const logout = async () => { 
    if (isSupabaseConfigured()) {
        await supabase.auth.signOut();
    }
    localStorage.removeItem('rx_history_cache');
    window.location.reload(); 
  };

  return { user, isLoggedIn, login, logout, loading };
};

import { supabase } from '../lib/supabaseClient.ts';
import { PrescriptionData } from '../types.ts';
import * as localDB from './localDatabaseService.ts';
import * as storageService from './storageService.ts';

// Helper to check if string is a valid UUID
const isUUID = (str: string) => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(str);

/**
 * Saves a prescription. 
 * If user is logged in: uploads assets -> saves to Cloud DB.
 * If user is guest: saves to Local DB.
 */
export const savePrescription = async (data: PrescriptionData): Promise<void> => {
  // Use getSession for broader compatibility as per engineering requirement
  const { data: { session } } = await supabase.auth.getSession();
  const user = session?.user;

  if (!user) {
    console.log("User not logged in, saving to local DB");
    await localDB.saveToLocalDB(data);
    return;
  }

  console.log(`Saving prescription for user: ${user.id}`);

  // 1. Upload Assets (Image & PDF)
  const { imagePath, pdfPath } = await storageService.uploadPrescriptionAssets(user.id, data);

  // 2. Prepare Data for Postgres
  const { imageUrls, ...cleanData } = data;

  const payload: any = {
    user_id: user.id,
    patient_name: data.patientName || 'Unknown',
    date: data.date ? new Date(data.date).toISOString() : new Date().toISOString(),
    status: data.status,
    full_data: cleanData,
    image_path: imagePath,
    pdf_path: pdfPath
  };

  let query;

  if (isUUID(data.id)) {
    // UPDATE: ID is a UUID, so we treat it as an existing record.
    payload.id = data.id;
    query = supabase.from('prescriptions').upsert(payload);
  } else {
    // INSERT: ID is temporary (e.g. 'rx-123'), let Supabase generate a new UUID.
    query = supabase.from('prescriptions').insert([payload]);
  }

  const { error: dbError } = await query;

  if (dbError) {
      console.error("Database Save Error:", dbError);
      throw new Error(`Failed to save prescription: ${dbError.message}`);
  }
};

/**
 * Retrieves all prescriptions.
 * If user is logged in: fetches from Cloud DB.
 * If user is guest: fetches from Local DB.
 */
export const getAllPrescriptions = async (): Promise<PrescriptionData[]> => {
  const { data: { session } } = await supabase.auth.getSession();
  const user = session?.user;

  if (!user) {
    return await localDB.getFromLocalDB();
  }

  const { data, error } = await supabase
    .from('prescriptions')
    .select('*')
    .eq('user_id', user.id)
    .order('created_at', { ascending: false });

  if (error) {
    console.error("Error fetching prescriptions:", error);
    return [];
  }

  return data.map((row: any) => {
    const pData = row.full_data;
    return {
      ...pData,
      id: row.id, // Must use the DB UUID
      status: row.status,
      imageUrls: row.image_path ? [row.image_path] : (pData.imageUrls || []),
      pdfUrl: row.pdf_path,
      timestamp: row.created_at // Use server timestamp for accurate history
    };
  });
};

/**
 * Deletes a prescription.
 * If user is logged in: deletes from Cloud DB.
 * If user is guest: deletes from Local DB.
 */
export const deletePrescription = async (id: string): Promise<void> => {
  const { data: { session } } = await supabase.auth.getSession();
  const user = session?.user;

  if (!user) {
    await localDB.deleteFromLocalDB(id);
    return;
  }

  const { error } = await supabase
    .from('prescriptions')
    .delete()
    .eq('id', id)
    .eq('user_id', user.id);

  if (error) {
      console.error("Delete failed:", error);
      throw error;
  }
};

import { createClient } from '@supabase/supabase-js';

// CLINICAL SECURITY: Source from Vite environment. 
// Use placeholders to ensure createClient doesn't throw during the build baking phase.
const ENV_URL = (import.meta as any).env?.VITE_SUPABASE_URL;
const ENV_KEY = (import.meta as any).env?.VITE_SUPABASE_ANON_KEY;

const PLACEHOLDER_URL = "https://clinical-infrastructure-offline.supabase.co";
const PLACEHOLDER_KEY = "offline-key-placeholder";

/**
 * CLINICAL SAFETY: Validates whether the environment has provided real keys.
 * This is used for UI hinting, not for blocking the execution path.
 */
export const isSupabaseConfigured = (): boolean => {
    return !!(ENV_URL && ENV_KEY && ENV_URL.startsWith('https://') && ENV_URL !== PLACEHOLDER_URL);
};

let clientInstance: any = null;

/**
 * DYNAMIC INITIALIZATION:
 * Returns a real Supabase client. If keys are missing, it returns a client
 * configured with placeholders that will fail gracefully at the network layer.
 */
export const getSupabase = () => {
    if (!clientInstance) {
        const url = ENV_URL || PLACEHOLDER_URL;
        const key = ENV_KEY || PLACEHOLDER_KEY;
        clientInstance = createClient(url, key);
    }
    return clientInstance;
};

// Export the singleton instance
export const supabase = getSupabase();

import { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient.ts';

export type User = { name: string; email: string; id: string };
export type CloudStatus = 'DISCOVERING' | 'ENABLED' | 'LOCAL_ONLY' | 'DEGRADED';

export const useAuthSession = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);
  const [cloudStatus, setCloudStatus] = useState<CloudStatus>('DISCOVERING');

  const timeoutRef = useRef<any>(null);

  useEffect(() => {
    let mounted = true;

    const bootstrap = async () => {
        // 1. Capability Discovery
        if (!isSupabaseConfigured()) {
            if (mounted) {
                setCloudStatus('LOCAL_ONLY');
                setLoading(false);
            }
            return;
        }

        // 2. Resilience Timeout
        timeoutRef.current = setTimeout(() => {
            if (loading && mounted) {
                console.warn("Clinical Infrastructure: Delayed response from cloud node.");
                setCloudStatus('DEGRADED');
            }
        }, 5000);

        try {
            // 3. Initial Session Check
            const { data: { session }, error } = await supabase.auth.getSession();

            if (error) throw error;

            if (mounted) {
                setCloudStatus('ENABLED');
                if (session?.user) {
                    setUser({
                        name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
                        email: session.user.email || '',
                        id: session.user.id
                    });
                    setIsLoggedIn(true);
                }
            }
        } catch (err) {
            console.error("Cloud Handshake Failed:", err);
            if (mounted) setCloudStatus('DEGRADED');
        } finally {
            if (mounted) {
                clearTimeout(timeoutRef.current);
                setLoading(false);
            }
        }
    };

    bootstrap();

    // 4. Auth State Listener
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (!mounted) return;

      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
        setCloudStatus('ENABLED');
      } else {
        setUser(null);
        setIsLoggedIn(false);
      }
    });

    return () => {
      mounted = false;
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      subscription.unsubscribe();
    };
  }, []);

  const logout = async () => { 
    if (isSupabaseConfigured()) {
        await supabase.auth.signOut();
    }
    localStorage.removeItem('rx_history_cache');
    window.location.reload(); 
  };

  return { user, isLoggedIn, logout, loading, cloudStatus };
};

