    e.preventDefault();
    setError('');

    if (!isConfigured) {
        setError("Clinical Environment Error: Cloud keys missing. Please verify server configuration.");
        return;
    }

    setLoading(true);
    try {
        const { data, error: authError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (authError) {
          setError(authError.message);
        } else if (data.user) {
          onLogin({ 
            name: data.user.user_metadata?.full_name || email.split('@')[0], 
            email: data.user.email || '' 
          });
        }
    } catch (e) {
        setError("Network Error: Could not connect to the clinical auth node.");
    } finally {
        setLoading(false);
    }
  };

